# Also fix the html lang attribute in all files (the COMMON pass already does this,
# but double-check it is applied)
GLOBAL_FIXES = [
    ('<html lang="en">', '<html lang="es">'),
]

for fname, replacements in FILES.items():
    path = os.path.join('es', fname)
    if not os.path.exists(path):
        print(f'SKIP (not found): {path}')
        continue
    with open(path, 'r', encoding='utf-8') as f:
        html = f.read()
    for old, new in GLOBAL_FIXES:
        html = html.replace(old, new)
    count = 0
    for old, new in replacements:
        if old in html:
            html = html.replace(old, new)
            count += 1
    with open(path, 'w', encoding='utf-8') as f:
        f.write(html)
    print(f'OK ({count} replacements): es/{fname}')

print('\nDetailed translations done.')
